ut freq: HashMap&lt;String, usize&gt; = HashMap::new(); for window in words.windows(n) { let gram = window.join(&#34; &#34;); *freq.entry(gram).or_insert(0) += 1; } let mut result: Vec&lt;_&gt; = freq.into_iter().collect(); result.sort_by(|a, b| b.1.cmp(&amp;a.1).then_with(|| a.0.cmp(&amp;b.0))); result } fn main() { let text = r#&#34; Rust is a multi-paradigm, general-purpose programming language. Rust emphasizes safety, especially safe concurrency. Rust is syntactically similar to C++, but provides memory safety. Rust is used by many companies including Firefox, Dropbox, and Cloudflare. The Rust community is vibrant and welcoming. Learning Rust takes time but the investment pays off. Rust has zero-cost abstractions and move semantics. The borrow checker ensures memory safety without garbage collection. &#34;#; println!(&#34;═══════════════════════════════════════════&#34;); println!(&#34; 文本分析工具&#34;); println!(&#34;═══════════════════════════════════════════&#34;); // 基本统计 let words: Vec&lt;_&gt; = text.split_whitespace().collect(); println!(&#34;
