等待现有连接完成...&#34;); timeout(Duration::from_secs(5), self.shutdown_complete.recv()).await.ok(); *self.state.borrow_mut() = ServerState::Stopped; println!(&#34;✅ 服务器已停止&#34;); Ok(()) } /// 请求关闭 fn shutdown(&amp;self) { *self.state.borrow_mut() = ServerState::ShuttingDown; let _ = self.state.send(ServerState::ShuttingDown); } } /// 关闭令牌 struct ShutdownToken { state_rx: watch::Receiver&lt;ServerState&gt;, shutdown_rx: broadcast::Receiver&lt;()&gt;, } impl ShutdownToken { fn is_shutting_down(&amp;self) -&gt; bool { *self.state_rx.borrow() != ServerState::Running } async fn wait_for_shutdown(&amp;mut self) { let _ = self.shutdown_rx.recv().await; } } /// 处理连接 async fn handle_connection( socket: tokio::net::TcpStream, mut token: ShutdownToken, ) { println!(&#34;🔌 开始处理连接&#34;); // 模拟处理 for i in 0..5 { if token.is_shutting_down() { println!(&#34;🛑 连接处理被中断&#34;); return; } println!(&#34;📝 处理数据块 {}/5&#34;, i + 1); tokio::time::sleep(Duration::from_millis(500)).await; } println!(&#34;✅ 连接处理完成&#34;); // 通知完成 let _ = socket; // 实际代码中会发送信号 } #[tokio::main] async fn main() -&gt; Result&lt;(), Box&lt;dyn std::error::Error&gt;&gt; { let server = Arc::new(Server::new()); let server_clone = Arc::clone(&amp;server); // 在后台运行服务器 let server_handle = tokio::spawn(async move { let _ = server_clone.run(&#34;127.0.0.1:0&#34;).await; }); // 模拟运行 3 秒 tokio::time::sleep(Duration::from_secs(3)).await; // 请求关闭 println!(&#34;
