🛑 下载被取消&#34;); return Err(&#34;cancelled&#34;); } // 模拟下载一个块 sleep(Duration::from_millis(200)).await; downloaded = (downloaded + chunk_size).min(total); let elapsed = start.elapsed().as_secs_f64(); let speed = if elapsed &gt; 0.0 { downloaded as f64 / elapsed } else { 0.0 }; let progress = DownloadProgress { downloaded, total, speed, }; // 更新进度 let _ = self.progress_tx.send(progress); println!( &#34;📊 进度：{:.1}% ({:.2} KB/s) &#34;, progress.percent(), progress.speed / 1024.0 ); // 检查是否完成 if downloaded &gt;= total { println!(&#34;
✅ 下载完成！&#34;); return Ok(progress); } } } } /// 进度显示器 async fn display_progress(mut progress_rx: watch::Receiver&lt;DownloadProgress&gt;) { loop { match progress_rx.changed().await { Ok(_) =&gt; { let p = progress_rx.borrow(); print!( &#34;📊 进度：{:5.1}% | 已下载：{:6} KB | 速度：{:6.1} KB/s&#34;, p.percent(), p.downloaded / 1024, p.speed / 1024.0 ); } Err(_) =&gt; break, // 发送器已关闭 } } println!(); } #[tokio::main] async fn main() { println!(&#34;🚀 可取消下载演示
&#34;); let downloader = Downloader::new(1000000); let progress_rx = downloader.progress(); // 创建取消通道 let (cancel_tx, cancel_rx) = watch::channel(false); // 启动进度显示 let display_handle = tokio::spawn(display_progress(progress_rx)); // 启动下载 let download_handle = tokio::spawn({ let downloader = &amp;downloader; async move { downloader.download(&#34;https://example.com/file.zip&#34;, cancel_rx).await } }); // 模拟：下载 1.5 秒后取消 sleep(Duration::from_millis(1500)).await; println!(&#34;

